import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as t,e as i}from"./app-f07825a0.js";const a="/assets/1696559306266-205b0dd1.png",e={},c=i(`<h1 id="how-study" tabindex="-1"><a class="header-anchor" href="#how-study" aria-hidden="true">#</a> How Study</h1><h2 id="引言" tabindex="-1"><a class="header-anchor" href="#引言" aria-hidden="true">#</a> 引言</h2><p>活到老，学到老。可见学习是贯穿我们一辈子的事情。当谈到学习时，每个人都有自己独特的方式和方法。学习是一项复杂而又个性化的过程，它不仅仅是获取知识的途径，更是一种持续发展和提高的方式。无论是在学校里追求学位，还是在日常生活中不断充实自己，学习都是我们成长和成功的关键。但学习并不是一项静态的任务，而是一个动态的过程。它不仅仅局限于课堂上或书本中的知识，它包括了不断积累新的经验、掌握新的技能、拓宽自己的视野以及改善个人的素质。因此，学习不仅仅是一种任务，更是一种生活方式，一种不断进步和完善的精神追求。本篇笔记将为您提供一些关于如何学习的有用建议和技巧，帮助您在学习的道路上更加顺利和高效，希望能够为您的学习旅程增添一些启发和指导。无论您是一名学生、一名职场人士，还是一位终身学习者，这些建议都将有助于您更好地掌握学习的艺术。让我们一起踏上这个激动人心的学习之旅，不断提高自己，追求更好的未来。</p><h2 id="费曼学习法" tabindex="-1"><a class="header-anchor" href="#费曼学习法" aria-hidden="true">#</a> 费曼学习法</h2><p>费曼学习法是世界上公认最高效的学习方法。以下是我个人学习此方法之后的提炼总结和一些个人观点。</p><h3 id="我们学习时的问题" tabindex="-1"><a class="header-anchor" href="#我们学习时的问题" aria-hidden="true">#</a> 我们学习时的问题</h3><p><b style="color:#3e547d;"><strong>学习不够深入，没有抓住知识的本质</strong></b></p><p>老鹰大家都知道，但是要具体描述的话，可能我们就只知道它是动物，描述的话语50词可能都说不出。可见我们并不真正了解老鹰这个动物。只是知道这个名词看过相关的视频和图片而已。</p><p>由此可见</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>知道概念 != 掌握知识
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><b style="color:#6E8B74;"><strong>深入学习很重要，那我们如何深入学习呢？</strong></b></p><p>下图是美国缅因州国家训练实验室发布的学习金字塔。</p><figure><img src="`+a+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>看图知意，最高效的学习方法就是教授给其他人，这里的 &quot;其他人&quot;可以是你的朋友，你的家人，也可以是路边的小花小草，甚至也可以是你大脑中的那位意识体。</p><p><strong>以教验学，是费曼技巧的核心。</strong></p><p>教别人也是一门学问，尽量不要用专业术语去教，因为专业术语难懂不利于我们的理解。可以尝试着用自己的话，打比喻的方式教授给他人。</p><p>费曼和他爸爸之间的小故事：有一天小费曼问他爸爸恐龙有多大？</p><p>百科全书的回答：</p><blockquote><p>恐龙身高有25英尺，头有六英尺宽</p></blockquote><p>费曼爸爸的回答：</p><blockquote><p>要是恐龙站在咋家门前，它的头可以伸到咱家二楼窗户那里，但是它的脑袋却伸不进来。</p></blockquote><p>我们可以学习费曼爸爸的回答，把冰冷的数据变成形象的事物。</p><h3 id="费曼技巧的具体步骤" tabindex="-1"><a class="header-anchor" href="#费曼技巧的具体步骤" aria-hidden="true">#</a> 费曼技巧的具体步骤</h3><ol><li>选择要学的知识点，开始学习</li><li>用最简单的方式和最简单的语言教给别人</li><li>发现自己解释不清或者不能理解的地方，回头学习</li><li>总结，做到脱离资料能简练，完整地表达</li></ol><p>第一步中的选择知识去学习，最好是先把整体知识粗略的看一遍，然后再开始仔细学习，这样在我们的头脑中就有了这个知识点整体框架，不至于学的时候一脸懵。</p><h3 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h3><p>纸上得来终觉浅，绝知此事要躬行。实践是检验真理的唯一标准。所以，学会不等于会用。还是得会用。</p><h2 id="如何学习新知识点" tabindex="-1"><a class="header-anchor" href="#如何学习新知识点" aria-hidden="true">#</a> 如何学习新知识点</h2><p>我们在学习新的知识的时候，需要系统的学习，不能只了解它的概念，定义等。我们应该从它的发明人，它的由来，背景等开始学习。学习不同知识的时候我们需要了解的方面是不同的，如我们学习Git这个版本管理工具可以从简介、官网、下载、作用、命令、使用。这几个方面系统的学习它。但是我们学习篮球的时候肯定不会有下载，反而我们需要找教练。可见不同事物的学习方面是不同，由此我罗列出了下列几十个方面，供我们去选择。</p><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-0" disabled="disabled"><label class="task-list-item-label" for="task-item-0"> 官网</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-1" disabled="disabled"><label class="task-list-item-label" for="task-item-1"> 引言</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-2" disabled="disabled"><label class="task-list-item-label" for="task-item-2"> 简介</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-3" disabled="disabled"><label class="task-list-item-label" for="task-item-3"> 安装</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-4" disabled="disabled"><label class="task-list-item-label" for="task-item-4"> 案例</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-5" disabled="disabled"><label class="task-list-item-label" for="task-item-5"> 本质</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-6" disabled="disabled"><label class="task-list-item-label" for="task-item-6"> 条件</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-7" disabled="disabled"><label class="task-list-item-label" for="task-item-7"> 问题</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-8" disabled="disabled"><label class="task-list-item-label" for="task-item-8"> 前提</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-9" disabled="disabled"><label class="task-list-item-label" for="task-item-9"> 背景</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-10" disabled="disabled"><label class="task-list-item-label" for="task-item-10"> 概念</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-11" disabled="disabled"><label class="task-list-item-label" for="task-item-11"> 定义</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-12" disabled="disabled"><label class="task-list-item-label" for="task-item-12"> 意义</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-13" disabled="disabled"><label class="task-list-item-label" for="task-item-13"> 思想</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-14" disabled="disabled"><label class="task-list-item-label" for="task-item-14"> 思考</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-15" disabled="disabled"><label class="task-list-item-label" for="task-item-15"> 理念</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-16" disabled="disabled"><label class="task-list-item-label" for="task-item-16"> 比喻</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-17" disabled="disabled"><label class="task-list-item-label" for="task-item-17"> 作用</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-18" disabled="disabled"><label class="task-list-item-label" for="task-item-18"> 注意</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-19" disabled="disabled"><label class="task-list-item-label" for="task-item-19"> 组成</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-20" disabled="disabled"><label class="task-list-item-label" for="task-item-20"> 特点</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-21" disabled="disabled"><label class="task-list-item-label" for="task-item-21"> 基础</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-22" disabled="disabled"><label class="task-list-item-label" for="task-item-22"> 要求</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-23" disabled="disabled"><label class="task-list-item-label" for="task-item-23"> 使用</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-24" disabled="disabled"><label class="task-list-item-label" for="task-item-24"> 注意</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-25" disabled="disabled"><label class="task-list-item-label" for="task-item-25"> 规划</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-26" disabled="disabled"><label class="task-list-item-label" for="task-item-26"> 例题</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-27" disabled="disabled"><label class="task-list-item-label" for="task-item-27"> 实践</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-28" disabled="disabled"><label class="task-list-item-label" for="task-item-28"> 应用</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-29" disabled="disabled"><label class="task-list-item-label" for="task-item-29"> 练习</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-30" disabled="disabled"><label class="task-list-item-label" for="task-item-30"> 提问</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-31" disabled="disabled"><label class="task-list-item-label" for="task-item-31"> 讨论</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-32" disabled="disabled"><label class="task-list-item-label" for="task-item-32"> 教授</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-33" disabled="disabled"><label class="task-list-item-label" for="task-item-33"> 复盘</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-34" disabled="disabled"><label class="task-list-item-label" for="task-item-34"> 比赛</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-35" disabled="disabled"><label class="task-list-item-label" for="task-item-35"> 记忆</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-36" disabled="disabled"><label class="task-list-item-label" for="task-item-36"> 寻找老师或教练</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-37" disabled="disabled"><label class="task-list-item-label" for="task-item-37"> 能解决的问题</label></li></ul><p>如我们学习Spring这个框架，首先可以从上面的几十个方面选择出学习的步骤。然后按照步骤顺序一步一步的开始学习。我的选择是 官网 简介 意义 思想 使用 实践 练习 应用 思考 复盘 这几个方面系统的学习。</p><h2 id="关于记笔记" tabindex="-1"><a class="header-anchor" href="#关于记笔记" aria-hidden="true">#</a> 关于记笔记</h2><p>大学以前我都不习惯于做笔记，高中阶段没有系统的做过笔记，大多是不懂的随便在本上记记。那时候不觉得笔记有什么好的，有时间还不如多刷几道题。但自从大学开始学编程之后，才觉得笔记的好处。前端后端框架数据库，还有一些多的数不清的命令。这真不是看一遍就能记住并且熟练运用的。编程是个细致活，一步错了就运行不起来了。有时候你忘记了一个知识点，如果你不记笔记，你就能难找到解决方法，你明明就记得你在哪里学过了，但就是记不住具体的位置，这往往需要花费大量的时间去找解决方法。这时候笔记的重要性就体现出来了。现在的我学一个新知识是绝对不会学第二遍的。好记性不如烂笔头。</p><h2 id="关于复习" tabindex="-1"><a class="header-anchor" href="#关于复习" aria-hidden="true">#</a> 关于复习</h2><p>可以这么说复习是学习中必不可少的环节。人类遗忘事物的速度是很快的。不想遗忘的最有效方法就是复习。</p><h3 id="复习的时间点" tabindex="-1"><a class="header-anchor" href="#复习的时间点" aria-hidden="true">#</a> 复习的时间点</h3><p>第一次：学习后的第二天</p><p>第二次：第一次复习一周后</p><p>第三次：第二次复习二周后</p><p>第四次：第三次复习一个月后</p><h3 id="总结-1" tabindex="-1"><a class="header-anchor" href="#总结-1" aria-hidden="true">#</a> 总结</h3><blockquote><p>简单的事情重复做，重复做的事情认真做，认真做的事情坚持做。</p></blockquote>',42),b=[c];function k(d,m){return l(),t("div",null,b)}const p=s(e,[["render",k],["__file","How Study.html.vue"]]);export{p as default};
